import unittest
from math_utils import safe_divide

class TestRobustMath(unittest.TestCase):
    def test_zero(self):
        self.assertIsNone(safe_divide(10, 0))
    def test_types(self):
        with self.assertRaises(ValueError):
            safe_divide(10, 'abc')
    def test_strings(self):
        self.assertEqual(safe_divide(' 10 ', ' 2 '), 5.0)

if __name__ == '__main__':
    unittest.main()
